class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val intent = intent
        val action = intent.action
        val type = intent.type

        if (Intent.ACTION_SEND == action && type != null) {
            if ("text/plain" == type) {
                handleTextShare(intent)
            } else if (type.startsWith("image/")) {
                handleImageShare(intent)
            }
        }
        
        finish()
    }

    private fun handleTextShare(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            Log.d(TAG, "Received text: $sharedText")
            processSharedText(sharedText)
        }
    }

    private fun handleImageShare(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            Log.d(TAG, "Received image URI: $imageUri")
            processSharedImage(imageUri)
        }
    }

    private fun processSharedText(text: String) {
        // Process the shared text content
        if (text.startsWith("http")) {
            // Handle URL
            Log.d(TAG, "Processing URL: $text")
        } else {
            // Handle regular text
            Log.d(TAG, "Processing text: $text")
        }
    }

    private fun processSharedImage(uri: Uri) {
        try {
            val inputStream = contentResolver.openInputStream(uri)
            val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
            Log.d(TAG, "Processing image with dimensions: ${bitmap.width}x${bitmap.height}")
            
            // Convert bitmap to byte array if needed
            val byteArrayOutputStream = ByteArrayOutputStream()
            bitmap.compress(Bitmap.CompressFormat.JPEG, 100, byteArrayOutputStream)
            val imageBytes = byteArrayOutputStream.toByteArray()
            
            // Process image bytes
            processImageBytes(imageBytes)
        } catch (e: Exception) {
            Log.e(TAG, "Error processing image", e)
        }
    }

    private fun processImageBytes(bytes: ByteArray) {
        // Process the image bytes
        Log.d(TAG, "Image bytes length: ${bytes.size}")
    }
}